import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Allocate a fixed-size buffer
        byte[] buffer = new byte[10];

        // Copy the user input into the buffer with proper boundary checking
        for (int i = 0; i < Math.min(userInput.length(), buffer.length); i++) {
            buffer[i] = (byte) userInput.charAt(i);
        }

        System.out.println("Buffer overflow vulnerability successfully mitigated!");
    }
}

